    <thead>
      <tr>
        <th style="width: 5%;">NO</th>
        <th style="width: 45%;">DESCRIPTION</th>
        <th style="width: 10%;">QTY</th>
        <th style="width: 10%;">UoM</th>
        <th style="width: 15%;">UNIT PRICE</th>
        <th style="width: 15%;">AMOUNT</th>
      </tr>
    </thead>
    <tbody>
